```plantuml
@startuml

package "Bean" {

  class lable {
    □ int ID
    □ String info
  }

  note right of lable : 图书分类,用来控制添加或修改图书时\n控制器选项范围,不与book建立直接联系

  class borrowHis {
    □ Date returnDate
    □ Boolean flag
  }

  class user {
    □ String ID
    □ String pwd
    □ Date createTime
    □ byte status
  }

  class ticket {
    □ String title
    □ String info
    □ String adminID
  }

  class bookDetList {
    □ String ID
    □ Date borrowDate
    □ short deadline
    □ byte status
  }

  class root {
  }

  class borrower {
    □ String firstName
    □ String lastName
    □ String IDCardNo
    □ String email
    □ String m_phoneNumber
    □ String creditRating
  }

  class admin {
    □ String firstName
    □ String lastName
    □ String email
    □ Boolean root
  }

  class bookDetListInfo {
    □ byte number
  }

  class book {
    □ String ISBN
    □ String name
    □ String Label
    □ String logo
    □ String info
    □ float price
    □ String publisher
    □ String author
    □ Date publishDate
    □ short stock
    □ short Number
  }

  user "1" -- "N" ticket : 拥有或管理

  root --|> user : 继承
  borrower --|> user : 继承
  admin --|> user : 继承

  admin "1" -- "N" ticket : 管理

  bookDetList --|> borrowHis : 继承
  ticket "N" --o bookDetList : 包含

  bookDetList -- bookDetListInfo : 拥有
  bookDetListInfo *-- bookDetListInfo

  bookDetListInfo "1" -- "1" book : 记录

}

@enduml
```
